class DoublyLinkedListNode:
    def __init__(self, data):
        self.data = data
        self.next = None
        self.prev = None

    def insert_after(self, new_node):
        new_node.next = self.next
        if self.next:
            self.next.prev = new_node
        self.next = new_node
        new_node.prev = self

    def delete(self):
        if self.prev:
            self.prev.next = self.next
        if self.next:
            self.next.prev = self.prev

    def find_previous(self, data):
        current = self
        while current.prev:
            current = current.prev
            if current.data == data:
                return current
        return None

    def find_next(self, data):
        current = self
        while current.next:
            current = current.next
            if current.data == data:
                return current
        return None

    def find_last(self):
        current = self
        while current.next:
            current = current.next
        return current

    def reverse(self):
        current = self
        while current.next:
            current = current.next
        while current:
            current.next, current.prev = current.prev, current.next
            current = current.next

    def sort(self):
        current = self
        while current.next:
            current = current.next
        while current:
            if current.prev and current.data < current.prev.data:
                current.data, current.prev.data = current.prev.data, current.data
                current = current.prev
            else:
                current = current.next

    def merge(self, other_list):
        current = self
        while current.next:
            current = current.next
        current.next = other_list
        other_list.prev = current
        self.sort()

    def remove_duplicates(self):
        current = self
        while current:
            data = current.data
            runner = current.next
            while runner:
                if runner.data == data:
                    runner.delete()
                runner = runner.next
            current = current.next

    def find_kth_from_end(self, k):
        slow = self
        fast = self
        for _ in range(k):
            if fast.next:
                fast = fast.next
            else:
                return None
        while fast.next:
            fast = fast.next
            slow = slow.next
        return slow

    def split_into_odd_even_lists(self):
        odd_list = DoublyLinkedListNode(None)
        even_list = DoublyLinkedListNode(None)
        current = self
        count = 1
        while current:
            if count % 2 == 0:
                even_list.insert_after(DoublyLinkedListNode(current.data))
            else:
                odd_list.insert_after(DoublyLinkedListNode(current.data))
            current = current.next
            count += 1
        return odd_list.next, even_list.next

    def find_median(self):
        sorted_list = self
        sorted_list.sort()
        current = sorted_list
        count = 0
        while current:
            current = current.next
            count += 1
        middle = count // 2
        if count % 2 == 0:
            return (sorted_list.find_kth_from_end(middle).data + sorted_list.find_kth_from_end(middle - 1).data) / 2
        else:
            return sorted_list.find_kth_from_end(middle).data

    def rotate(self, positions):
        current = self
        last_node = current.find_last()
        for _ in range(positions):
            last_node.insert_after(DoublyLinkedListNode(current.data))
            current = current.next
            current.delete()
