            self.tail = node.prev
        else:
            node.next.prev = node.prev

    def search(self, value):
        curr = self.head
        while curr is not None:
            if curr.value == value:
                return curr
            curr = curr.next
        return None

    def reverse(self):
        curr = self.head
        while curr is not None:
            curr.prev, curr.next = curr.next, curr.prev
            curr = curr.prev

        self.head, self.tail = self.tail, self.head

