def fibonacci(n):
    def multiply_matrices(a, b):
        c = [[0, 0], [0, 0]]
        c[0][0] = a[0][0] * b[0][0] + a[0][1] * b[1][0]
        c[0][1] = a[0][0] * b[0][1] + a[0][1] * b[1][1]
        c[1][0] = a[1][0] * b[0][0] + a[1][1] * b[1][0]
        c[1][1] = a[1][0] * b[0][1] + a[1][1] * b[1][1]
        return c

    def power_matrix(matrix, power):
        if power == 1:
            return matrix
        elif power % 2 == 0:
            half_power = power // 2
            half_matrix = power_matrix(matrix, half_power)
            return multiply_matrices(half_matrix, half_matrix)
        else:
            half_power = power // 2
            half_matrix = power_matrix(matrix, half_power)
            return multiply_matrices(multiply_matrices(half_matrix, half_matrix), matrix)

    if n <= 0:
        return 0

    fibonacci_matrix = [[1, 1], [1, 0]]
    result_matrix = power_matrix(fibonacci_matrix, n - 1)
    return result_matrix[0][0]
