def is_prime(n):
    if n <= 1:
        return False
    if n <= 3:
        return True
    if n % 2 == 0 or n % 3 == 0:
        return False
    i = 5
    while i * i <= n:
        if n % i == 0 or n % (i + 2) == 0:
            return False
        i += 6
    return True

def primes_in_range(start, end):
    primes = []
    limit = math.isqrt(end) + 1
    sieve = [True] * (limit + 1)
    for p in range(2, limit + 1):
        if sieve[p]:
            for i in range(p * p, limit + 1, p):
                sieve[i] = False
            for i in range(max(p * p, (start // p) * p), end + 1, p):
                if i >= start:
                    primes.append(i)
    for num in range(max(limit, start), end + 1):
        if is_prime(num):
            primes.append(num)
    return primes
