def calculate_levenshtein_distance(str1, str2):
    dp = [[0] * (len(str2) + 1) for _ in range(len(str1) + 1)]

    for i in range(len(str1) + 1):
        dp[i][0] = i

    for j in range(len(str2) + 1):
        dp[0][j] = j

    for i in range(1, len(str1) + 1):
        for j in range(1, len(str2) + 1):
            if str1[i - 1] == str2[j - 1]:
                dp[i][j] = dp[i - 1][j - 1]
            else:
                dp[i][j] = 1 + min(dp[i][j - 1], dp[i - 1][j], dp[i - 1][j - 1])

    min_operations = dp[len(str1)][len(str2)]

    print("Minimum operations required:", min_operations)

    paths = []
    stack = [(str1, str2, [], len(str1), len(str2))]

    while stack:
        s1, s2, path, i, j = stack.pop()

        if i == 0 and j == 0:
            paths.append(path)

        elif i == 0:
            path.append(f"Step {len(str2) - j + 1}: {s2[:j - 1]} -> {s2[:j]} (insert '{s2[j - 1]}' at the end)")
            stack.append((s1, s2, path.copy(), i, j - 1))

        elif j == 0:
            path.append(f"Step {len(str1) - i + 1}: {s1[:i - 1]} -> {s1[:i]} (delete '{s1[i - 1]}')")
            stack.append((s1, s2, path.copy(), i - 1, j))

        else:
            if str1[i - 1] == str2[j - 1]:
                stack.append((s1, s2, path.copy(), i - 1, j - 1))
            else:
                stack.append((s1, s2, path.copy(), i - 1, j))
                stack.append((s1, s2, path.copy(), i, j - 1))
                stack.append((s1, s2, path.copy(), i - 1, j - 1))
                path.append(f"Step {len(str1) - i + 1}: {s1[:i - 1]} -> {s1[:i]} (substitute '{s2[j - 1]}' for '{s1[i - 1]}')")
                stack.append((s1, s2, path.copy(), i - 1, j - 1))

    for i, path in enumerate(paths):
        print(f"\nPath {i+1}:")
        for step in path[::-1]:
            print(step)

