```python
import math

# Helper function to check if a number is prime
def is_prime(n):
    if n <= 1:
        return False
    if n == 2 or n == 3:
        return True
    if n % 2 == 0 or n % 3 == 0:
        return False
    sqrt_n = int(math.sqrt(n)) + 1
    for i in range(6, sqrt_n, 6):
        if n % (i - 1) == 0 or n % (i + 1) == 0:
            return False
    return True

# Method to calculate the nth Fibonacci number
def fibonacci(n):
    if n <= 0:
        return 0

    a, b = 0, 1
    for _ in range(2, n + 1):
        a, b = b, a + b

    return b

# Method to get the nth Fibonacci number for a prime number greater than 10^9
def nth_fibonacci_prime(n):
    prime_count = 0
    i = 0

    while prime_count < n:
        i += 1
        if is_prime(i):
            prime_count += 1

    return fibonacci(i)

