import random
import statistics

class DataCleaner:
    def __init__(self, input_data):
        self.input_data = input_data
        self.cleaned_data = []

    def clean_age(self, age):
        try:
            age = int(age)
            return age
        except ValueError:
            return -1

    def clean_income(self, income):
        income = income.replace('$', '').replace(',', '')
        try:
            income = int(income)
            return income
        except ValueError:
            return -1

    def clean_address(self, address):
        address = re.sub(r'[^a-zA-Z]+', '', address)
        return address

    def check_age_range(self, age):
        age_values = [sample['age'] for sample in self.input_data if sample['age'] != -1]
        if age < min(age_values) or age > max(age_values):
            return statistics.median(age_values)
        return age

    def normalize_income(self, income):
        income_values = [sample['income'] for sample in self.input_data if sample['income'] != -1]
        income_min = min(income_values)
        income_max = max(income_values)
        normalized_income = (income - income_min) / (income_max - income_min)
        return normalized_income

    def one_hot_encode_address(self, address):
        unique_addresses = list(set([sample['address'] for sample in self.input_data]))
        encoded_address = {}
        for unique_address in unique_addresses:
            if unique_address == address:
                encoded_address[unique_address] = 1
            else:
                encoded_address[unique_address] = 0
        return encoded_address

    def handle_missing_address(self, address):
        addresses = [sample['address'] for sample in self.input_data if sample['address'] != '']
        if address == '':
            return max(set(addresses), key=addresses.count)
        return address

    def add_label(self):
        for sample in self.cleaned_data:
            sample['label'] = random.choice(['A', 'B'])

    def clean_data(self):
        self._clean_data_helper(self.input_data)
        self.add_label()
        return self.cleaned_data

    def _clean_data_helper(self, input_data):
        if len(input_data) == 0:
            return
        else:
            sample = input_data[0]
            cleaned_sample = {}
            cleaned_sample['age'] = self.check_age_range(self.clean_age(sample['age']))
            cleaned_sample['income'] = self.normalize_income(self.clean_income(sample['income']))
            cleaned_sample['address'] = self.one_hot_encode_address(self.handle_missing_address(self.clean_address(sample['address'])))
            self.cleaned_data.append(cleaned_sample)
            self._clean_data_helper(input_data[1:])

